import React from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Star } from 'lucide-react';

export default function Testimonials() {
  const navigate = useNavigate();

  const testimonials = [
    {
      name: 'John Smith',
      text: 'The alumni network helped me find my dream job!',
      year: '2018',
    },
    {
      name: 'Sarah Johnson',
      text: 'Great connections and wonderful community.',
      year: '2019',
    },
    {
      name: 'Mike Davis',
      text: 'Best networking platform for alumni.',
      year: '2020',
    },
  ];

  return (
    <div className="min-h-screen bg-gray-50 p-4">
      <button onClick={() => navigate('/dashboard')} className="flex items-center gap-2 text-blue-600 mb-8">
        <ArrowLeft className="w-5 h-5" /> Back
      </button>
      <div className="max-w-4xl mx-auto">
        <h1 className="text-3xl font-bold text-gray-900 mb-8">Testimonials</h1>
        <div className="space-y-4">
          {testimonials.map((testimonial, i) => (
            <div key={i} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-start gap-2 mb-2">
                {[...Array(5)].map((_, j) => (
                  <Star key={j} className="w-4 h-4 text-yellow-400 fill-yellow-400" />
                ))}
              </div>
              <p className="text-gray-900 mb-3">"{testimonial.text}"</p>
              <p className="text-gray-600">- {testimonial.name}, Class of {testimonial.year}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
